    return [
      "To reach an admin:",
      ADMIN_CONTACT_GUIDANCE,
      "",
      "Group admin tools are coming soon.",
    ].join("\n");
  }

  return [
    "To reach an admin:",
    ADMIN_CONTACT_GUIDANCE,
    "",
    "Tip: include the topic, your question, and any urgent details.",
  ].join("\n");
}

